import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ editingTour, onClose, onSuccess }) => {
  const { user } = useAuth();
  const [formData, setFormData] = useState({
    title: '', location: '', startDate: '', endDate: '', description: '',
    importantNotes: '', capacity: '', price: '', discount: '', status: 'Available'
  });

  useEffect(() => {
    if (editingTour) setFormData({ ...editingTour });
  }, [editingTour]);

  return (
    <div className="flex flex-col min-h-screen bg-white font-sans">
      {/* Header */}
      <div className="flex justify-between items-center p-5 border-b sticky top-0 bg-white z-10">
        <button onClick={onClose} className="text-2xl text-gray-600">←</button>
        <h1 className="text-lg font-black text-gray-800">Add Tour Package</h1>
        <button onClick={onClose} className="text-2xl">🏠</button>
      </div>

      <form className="p-6 space-y-6 overflow-y-auto flex-1 text-[13px]">
        {/* Title */}
        <div>
          <label className="block font-bold text-gray-700 mb-2">Tour Title</label>
          <input type="text" placeholder="Enter tour title" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})}
            className="w-full p-4 border border-gray-100 rounded-xl bg-white shadow-sm focus:ring-2 focus:ring-green-400 outline-none" />
        </div>

        {/* Date Row */}
        <div className="flex space-x-4">
          <div className="flex-1">
            <label className="block font-bold text-gray-700 mb-2">Start Date</label>
            <input type="date" className="w-full p-4 border border-gray-100 rounded-xl text-gray-400 bg-white" />
          </div>
          <div className="flex-1">
            <label className="block font-bold text-gray-700 mb-2">End Date</label>
            <input type="date" className="w-full p-4 border border-gray-100 rounded-xl text-gray-400 bg-white" />
          </div>
        </div>

        {/* Description */}
        <div>
          <label className="block font-bold text-gray-700 mb-2">What is it about</label>
          <textarea rows="4" placeholder="Enter description" className="w-full p-4 border border-gray-100 rounded-xl bg-white" />
        </div>

        {/* Important Notes */}
        <div>
          <label className="block font-bold text-gray-700 mb-2">Important Notes:</label>
          <textarea rows="3" placeholder="Enter Important Notes of the tour" className="w-full p-4 border border-gray-100 rounded-xl bg-white" />
        </div>

        {/* Upload Box - 還原截圖虛線設計 */}
        <div>
          <label className="block font-bold text-gray-700 mb-2">Upload cover picture</label>
          <div className="border-2 border-dashed border-gray-200 rounded-2xl p-10 text-center bg-gray-50 flex flex-col items-center cursor-pointer">
            <div className="bg-white p-3 rounded-full shadow-sm mb-2 text-gray-400">☁️</div>
            <p className="font-bold text-gray-800 text-sm">Click to upload</p>
            <p className="text-[10px] text-gray-400 uppercase mt-1">SVG, PNG, JPG or GIF (max. 800x400px)</p>
          </div>
        </div>

        {/* Stats Row */}
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-2">
            <label className="block font-bold text-gray-700 mb-1">Capacity (/day)</label>
            <input type="number" placeholder="Enter the maximum daily capacity" className="w-full p-4 border border-gray-100 rounded-xl" />
          </div>
          <div>
            <label className="block font-bold text-gray-700 mb-1">Price (in AUD)</label>
            <input type="number" placeholder="$ Enter price" className="w-full p-4 border border-gray-100 rounded-xl" />
          </div>
          <div>
            <label className="block font-bold text-gray-700 mb-1">Discount</label>
            <input type="number" placeholder="$ Enter price" className="w-full p-4 border border-gray-100 rounded-xl" />
          </div>
        </div>

        {/* Status Dropdown */}
        <div>
          <label className="block font-bold text-gray-700 mb-2">Status</label>
          <select className="w-full p-4 border border-gray-100 rounded-xl appearance-none bg-white">
            <option>Available</option>
            <option>Unavailable</option>
          </select>
        </div>

        {/* Submit Button */}
        <button type="submit" className="w-full bg-[#00A651] text-white font-bold py-5 rounded-2xl shadow-xl shadow-green-100 active:scale-95 transition-all">
          Submit
        </button>
      </form>
    </div>
  );
};

export default TourForm;
